decimal sumEggsPerLiveFemale = 0;
int countEggsPerLiveFemale = 0;
decimal avgEggsPerLiveFemale = 0;
decimal sumNestedEggs = 0;
decimal sumFloorEggs = 0;
decimal sumPOL = 0;
decimal sumPercent = 0;
int countRows = 0;

decimal sumRowPercent = 0;
int validRowCount = 0;
decimal sumHatchingPercent = 0;
int validRowCountHat = 0;
decimal sumFeedPerBird = 0;
int validRowCountFeedBird = 0;
decimal sumMaleFeedPerBird = 0;
int maleRowCount = 0;
decimal totalwaterConsumption =0;
decimal TotaLiveFemaleAndMale = 0;
private void xrTableCell15_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal nestedEggs = 0;
decimal floorEggs = 0;
decimal totalEggs = 0;
decimal liveFemale = 0;
decimal result = 0;

// --- Read NestedEggs ---
object v = GetCurrentColumnValue("NestedEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out nestedEggs);

// --- Read FloorEggs ---
v = GetCurrentColumnValue("FloorEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out floorEggs);

// --- TotalEggs ---
totalEggs = nestedEggs + floorEggs;

// --- Read rf_LiveFemale ---
v = GetCurrentColumnValue("rf_LiveFemale");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out liveFemale);

// --- Equation ---
if (liveFemale > 0)
    result = (totalEggs / liveFemale) * 100m;

// --- Assign result ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal nestedEggs = 0;
decimal floorEggs = 0;
decimal totalEggs = 0;
decimal liveFemale = 0;
decimal rowValue = 0;

// NestedEggs
object v = GetCurrentColumnValue("NestedEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out nestedEggs);

// FloorEggs
v = GetCurrentColumnValue("FloorEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out floorEggs);

// TotalEggs
totalEggs = nestedEggs + floorEggs;

// rf_LiveFemale
v = GetCurrentColumnValue("rf_LiveFemale");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out liveFemale);

// Row equation
if (liveFemale > 0)
{
    rowValue = (totalEggs / liveFemale) * 100m;

    // Accumulate for average
    sumEggsPerLiveFemale += rowValue;
    countEggsPerLiveFemale++;
}


decimal pol = 0;



// --- POL ---
v = GetCurrentColumnValue("POL");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out pol);

// --- Accumulate sums ---
sumNestedEggs += nestedEggs;
sumFloorEggs += floorEggs;
sumPOL += pol;

decimal percent = 0;


// Equation
if (totalEggs > 0)
{
    percent = (floorEggs / totalEggs) * 100m;

    // accumulate for AVG
    sumPercent += percent;
    countRows++;
}
decimal brokenEggs = 0;
decimal deformityEggs = 0;
decimal destroyedEggs = 0;
decimal dirtyEggs = 0;
decimal doubleYolkEggs = 0;
decimal overWeightEggs = 0;
decimal smallEggs = 0;
decimal softShellEggs = 0;
decimal floorRejectAdj = 0;
decimal rowPercent = 0;



// --- Read rejection fields ---
v = GetCurrentColumnValue("BrokenEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out brokenEggs);
v = GetCurrentColumnValue("DeformityEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out deformityEggs);
v = GetCurrentColumnValue("DestroyedEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out destroyedEggs);
v = GetCurrentColumnValue("DirtyEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out dirtyEggs);
v = GetCurrentColumnValue("DoubleYolkEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out doubleYolkEggs);
v = GetCurrentColumnValue("OverWeightEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out overWeightEggs);
v = GetCurrentColumnValue("SmallEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out smallEggs);
v = GetCurrentColumnValue("SoftShellEggs");
if (v != null && v != DBNull.Value) decimal.TryParse(v.ToString(), out softShellEggs);

// --- Floor rejection adjustment ---
v = GetCurrentColumnValue("HatchingFloorG_A");
if (v != null && v != DBNull.Value)
{
    decimal temp = 0;
    decimal.TryParse(v.ToString(), out temp);
    floorRejectAdj = floorEggs - temp;
}

// --- TotalRejectEggs for this row ---
decimal rowRejectEggs = brokenEggs + deformityEggs + destroyedEggs +
                        dirtyEggs + doubleYolkEggs + overWeightEggs +
                        smallEggs + softShellEggs + floorRejectAdj;

// --- Calculate row percentage ---
if (totalEggs > 0)
{
    rowPercent = (rowRejectEggs * 100m) / totalEggs;

    // accumulate for AVG
    sumRowPercent += rowPercent;
    validRowCount++;
}

decimal hatchingEggs = 0;
decimal hatchingFloorA = 0;
decimal hatchingFloorB = 0;

decimal totalHatchingEggs = 0;
decimal rowPercentHat = 0;

// --- Read Hatching Eggs ---
v = GetCurrentColumnValue("HatchingEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out hatchingEggs);

v = GetCurrentColumnValue("HatchingFloorG_A");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out hatchingFloorA);

v = GetCurrentColumnValue("HatchingFloorG_B");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out hatchingFloorB);

// --- Total Hatching Eggs ---
totalHatchingEggs = hatchingEggs + hatchingFloorA + hatchingFloorB;

// --- Calculate row % ---
if (totalEggs > 0)
{
    rowPercentHat = (totalHatchingEggs * 100m) / totalEggs;

    // --- Accumulate for AVG ---
    sumHatchingPercent += rowPercentHat ;
    validRowCountHat++;
}

// --- Declare row variables ---
decimal femaleFeed = 0;
decimal rowValuefemaleFeed = 0;

// --- Read FemaleFeed safely ---
 v = GetCurrentColumnValue("FemaleFeed");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out femaleFeed);


// --- Calculate row Feed per Bird x 1000 ---
if (liveFemale > 0)
{
    rowValuefemaleFeed = (femaleFeed / liveFemale) * 1000m;

    // --- Accumulate for AVG ---
    sumFeedPerBird += rowValuefemaleFeed ;
    validRowCountFeedBird++;
}


// --- Declare variables ---
decimal maleFeed = 0;
decimal liveMale = 0;
decimal result = 0;

// --- Read MaleFeed safely ---
v = GetCurrentColumnValue("MaleFeed");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out maleFeed);

// --- Read LiveMale safely ---
v = GetCurrentColumnValue("rf_LiveMale");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out liveMale);

// --- Calculate ---
if (liveMale > 0)
    result = (maleFeed / liveMale) * 1000m;

if (liveMale > 0)
{
    sumMaleFeedPerBird += result;
    maleRowCount++;
}
decimal totalLiveFemale = 0;
decimal totalLiveMale = 0;

totalLiveFemale += liveFemale;
totalLiveMale += liveMale;
decimal waterConsumption = 0;
// --- Read WaterConsumption ---
v = GetCurrentColumnValue("WaterConsumption");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out waterConsumption);

totalwaterConsumption += waterConsumption;
TotaLiveFemaleAndMale = totalLiveFemale + totalLiveMale ;
}

private void xrTableCell39_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    if (countEggsPerLiveFemale > 0)
    avgEggsPerLiveFemale = sumEggsPerLiveFemale / countEggsPerLiveFemale;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = avgEggsPerLiveFemale.ToString("0.##");
}

