private void xrTableCell25_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare variables ---
decimal nestedEggs = 0;
decimal floorEggs = 0;
decimal totalEggs = 0;

decimal brokenEggs = 0;
decimal deformityEggs = 0;
decimal destroyedEggs = 0;
decimal dirtyEggs = 0;
decimal doubleYolkEggs = 0;
decimal overWeightEggs = 0;
decimal smallEggs = 0;
decimal softShellEggs = 0;
decimal floorRejectAdj = 0;

decimal totalRejectEggs = 0;
decimal result = 0;

// --- Read NestedEggs ---
object v = GetCurrentColumnValue("NestedEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out nestedEggs);

// --- Read FloorEggs ---
v = GetCurrentColumnValue("FloorEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out floorEggs);

// --- TotalEggs ---
totalEggs = nestedEggs + floorEggs;

// --- Read rejection fields ---
v = GetCurrentColumnValue("BrokenEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out brokenEggs);

v = GetCurrentColumnValue("DeformityEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out deformityEggs);

v = GetCurrentColumnValue("DestroyedEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out destroyedEggs);

v = GetCurrentColumnValue("DirtyEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out dirtyEggs);

v = GetCurrentColumnValue("DoubleYolkEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out doubleYolkEggs);

v = GetCurrentColumnValue("OverWeightEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out overWeightEggs);

v = GetCurrentColumnValue("SmallEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out smallEggs);

v = GetCurrentColumnValue("SoftShellEggs");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out softShellEggs);

// --- Floor rejection adjustment ---
v = GetCurrentColumnValue("HatchingFloorG_A"); // used to calculate @RejectFloorEggs
if (v != null && v != DBNull.Value)
{
    decimal temp = 0;
    decimal.TryParse(v.ToString(), out temp);
    floorRejectAdj = floorEggs - temp;
}

// --- TotalRejectEggs ---
totalRejectEggs = brokenEggs + deformityEggs + destroyedEggs + dirtyEggs +
                  doubleYolkEggs + overWeightEggs + smallEggs + softShellEggs +
                  floorRejectAdj;

// --- Calculate % ---
if (totalEggs != 0)
    result = (totalRejectEggs * 100m) / totalEggs;

// --- Assign to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");

}

