private void xrTableCell82_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare variables ---
decimal waterConsumption = 0;
decimal liveFemale = 0;
decimal liveMale = 0;
decimal totalLive = 0;
decimal result = 0;

// --- Read WaterConsumption ---
object v = GetCurrentColumnValue("WaterConsumption");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out waterConsumption);

// --- Read LiveFemale ---
v = GetCurrentColumnValue("rf_LiveFemale");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out liveFemale);

// --- Read LiveMale ---
v = GetCurrentColumnValue("rf_LiveMale");
if (v != null && v != DBNull.Value)
    decimal.TryParse(v.ToString(), out liveMale);

// --- Total Live Birds ---
totalLive = liveFemale + liveMale;

// --- Equation ---
if (totalLive > 0)
    result = waterConsumption / totalLive;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");

}

private void xrTableCell99_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
 decimal WaterConsPerBirds = 0;

if (TotaLiveFemaleAndMale > 0)
    WaterConsPerBirds = totalwaterConsumption / TotaLiveFemaleAndMale ;

XRTableCell cell = sender as XRTableCell;
cell.Text = WaterConsPerBirds.ToString("0.##");

}
